from collections import defaultdict
from dataclasses import dataclass
from typing import List, Optional

@dataclass
class Ticket:
    ticket_id: str
    kb_article_id: Optional[str]
    resolved_at_tier: str  # "L1", "L2", "L3"

@dataclass
class ArticleStats:
    article_id: str
    linked: int = 0
    resolved_l1: int = 0

    @property
    def effectiveness(self) -> float:
        return self.resolved_l1 / self.linked if self.linked > 0 else 0.0

def compute_kb_effectiveness(tickets: List[Ticket]) -> List[ArticleStats]:
    stats: dict = defaultdict(lambda: ArticleStats(article_id=""))
    for t in tickets:
        if t.kb_article_id is None:
            continue
        s = stats[t.kb_article_id]
        s.article_id = t.kb_article_id
        s.linked += 1
        if t.resolved_at_tier == "L1":
            s.resolved_l1 += 1
    return sorted(stats.values(), key=lambda s: s.effectiveness)

tickets = [
    Ticket("T-001", "kb-agent-ctx-overflow-001", "L1"),
    Ticket("T-002", "kb-agent-ctx-overflow-001", "L1"),
    Ticket("T-003", "kb-agent-ctx-overflow-001", "L2"),
    Ticket("T-004", "kb-tool-call-fail-002", "L1"),
    Ticket("T-005", "kb-tool-call-fail-002", "L2"),
    Ticket("T-006", "kb-tool-call-fail-002", "L2"),
]

for r in compute_kb_effectiveness(tickets):
    print(f"{r.article_id}: {r.resolved_l1}/{r.linked} L1 resolves "
          f"(effectiveness={r.effectiveness:.0%})")

# Output:
# kb-tool-call-fail-002: 1/3 L1 resolves (effectiveness=33%)
# kb-agent-ctx-overflow-001: 2/3 L1 resolves (effectiveness=67%)
